import mysql.connector
import os
import sys
from pathlib import Path

def validate_file_path(file_path):
    """Validate file path to prevent directory traversal and ensure file exists"""
    try:
        # Resolve path to absolute path
        abs_path = Path(file_path).resolve()
        
        # Check if path is within allowed directory
        allowed_dir = Path("/data/imports").resolve()
        if not abs_path.is_relative_to(allowed_dir):
            raise ValueError("File path is outside allowed directory")
            
        # Check if file exists and is readable
        if not abs_path.exists():
            raise FileNotFoundError(f"File does not exist: {abs_path}")
            
        if not os.access(abs_path, os.R_OK):
            raise PermissionError(f"File is not readable: {abs_path}")
            
        return str(abs_path)
    except Exception as e:
        raise ValueError(f"Invalid file path: {e}")

def get_mysql_connection():
    """Establish secure MySQL connection with local_infile enabled"""
    try:
        connection = mysql.connector.connect(
            host='localhost',
            user='etl_user',
            password='secure_password_here',  # In production, use environment variables
            database='etl_database',
            autocommit=True,
            allow_local_infile=True,
            ssl_disabled=True  # Disable SSL for example, enable in production
        )
        return connection
    except mysql.connector.Error as e:
        print(f"Database connection failed: {e}")
        sys.exit(1)

def import_data_to_table(connection, file_path, table_name):
    """Import data using LOAD DATA INFILE"""
    try:
        cursor = connection.cursor()
        
        # Construct SQL statement with parameterized file path
        sql = f"""
        LOAD DATA INFILE '{file_path}' 
        INTO TABLE {table_name}
        FIELDS TERMINATED BY ','
        LINES TERMINATED BY '\\n'
        IGNORE 1 ROWS;
        """
        
        cursor.execute(sql)
        connection.commit()
        
        # Get affected rows
        rows_affected = cursor.rowcount
        cursor.close()
        
        return rows_affected
        
    except mysql.connector.Error as e:
        print(f"Import failed: {e}")
        connection.rollback()
        raise

def main():
    """Main execution function"""
    # Get file path from user input
    file_path = input("Enter the CSV file path to import: ").strip()
    
    # Validate file path
    try:
        validated_path = validate_file_path(file_path)
    except (ValueError, FileNotFoundError, PermissionError) as e:
        print(f"Input validation failed: {e}")
        sys.exit(1)
    
    # Get table name
    table_name = input("Enter target table name: ").strip()
    
    # Validate table name (simple validation)
    if not table_name or not table_name.replace('_', '').isalnum():
        print("Invalid table name")
        sys.exit(1)
    
    # Establish connection
    connection = get_mysql_connection()
    
    try:
        # Perform import
        rows_imported = import_data_to_table(connection, validated_path, table_name)
        print(f"Successfully imported {rows_imported} rows into table '{table_name}'")
        
    except Exception as e:
        print(f"Import process failed: {e}")
        sys.exit(1)
    finally:
        if connection.is_connected():
            connection.close()

if __name__ == "__main__":
    main()